import{_ as t,o as e,c as r,a2 as i}from"./chunks/framework.CQMe4Urg.js";const P=JSON.parse('{"title":"第 4 章 · LLM API 调用","description":"","frontmatter":{},"headers":[],"relativePath":"04-llm-api/index.md","filePath":"04-llm-api/index.md","lastUpdated":1776333512000}'),l={name:"04-llm-api/index.md"};function d(n,a,o,h,s,p){return e(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="第-4-章-·-llm-api-调用" tabindex="-1">第 4 章 · LLM API 调用 <a class="header-anchor" href="#第-4-章-·-llm-api-调用" aria-label="Permalink to &quot;第 4 章 · LLM API 调用&quot;">​</a></h1><p>会用 API 是 Agent 开发的基础。不管你的 Agent 架构多复杂，最终都要通过 API 与 LLM 交互。这一章从第一次调用开始，逐步覆盖到生产环境需要的全部能力。</p><h2 id="本章三层结构" tabindex="-1">本章三层结构 <a class="header-anchor" href="#本章三层结构" aria-label="Permalink to &quot;本章三层结构&quot;">​</a></h2><h3 id="初级-第一次-api-调用" tabindex="-1">初级：第一次 API 调用 <a class="header-anchor" href="#初级-第一次-api-调用" aria-label="Permalink to &quot;初级：第一次 API 调用&quot;">​</a></h3><p>掌握 Anthropic Claude 和 OpenAI 两套 API 的使用方法，理解请求响应结构，实现多轮对话。学完能独立调用 LLM API 完成各种任务。</p><h3 id="中级-流式输出与多模态" tabindex="-1">中级：流式输出与多模态 <a class="header-anchor" href="#中级-流式输出与多模态" aria-label="Permalink to &quot;中级：流式输出与多模态&quot;">​</a></h3><p>实现流式（Streaming）输出的前后端完整链路，掌握图片和 PDF 的多模态输入，学会设计统一的 LLM 适配层。学完能构建有流式打字效果的 AI 对话应用。</p><h3 id="高级-错误处理与生产化" tabindex="-1">高级：错误处理与生产化 <a class="header-anchor" href="#高级-错误处理与生产化" aria-label="Permalink to &quot;高级：错误处理与生产化&quot;">​</a></h3><p>掌握指数退避重试、速率控制、Token 截断等生产级策略，实现一个健壮的 LLM 客户端。学完能在生产环境中安全可靠地使用 LLM API。</p><h2 id="学完能做到" tabindex="-1">学完能做到 <a class="header-anchor" href="#学完能做到" aria-label="Permalink to &quot;学完能做到&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层级</th><th>学完你能</th></tr></thead><tbody><tr><td>初级</td><td>调用 Claude/OpenAI API，实现多轮对话，理解 Token 计费</td></tr><tr><td>中级</td><td>实现流式输出，处理图片/PDF 输入，设计多模型适配层</td></tr><tr><td>高级</td><td>构建带重试、限流、降级的生产级 LLM 客户端</td></tr></tbody></table><h2 id="前置要求" tabindex="-1">前置要求 <a class="header-anchor" href="#前置要求" aria-label="Permalink to &quot;前置要求&quot;">​</a></h2><ul><li>已注册 Anthropic 或 OpenAI 账号并获取 API Key</li><li>掌握 Python 基础语法和 async/await</li><li>了解 HTTP 协议基础</li></ul>',13)])])}const u=t(l,[["render",d]]);export{P as __pageData,u as default};
